// Hand-written gen functions for the OIDC + LDAP SSO additions.
// Mirrors the patterns from users.sql.go (Google/GitHub/Discord) and will
// be regenerated by sqlc when `make generate` is rewired.

package gen

import (
	"context"

	"github.com/google/uuid"
)

// ── OIDC ────────────────────────────────────────────────────────────────────

const getUserByOIDCSubject = `-- name: GetUserByOIDCSubject :one
SELECT id, username, email, password_hash, is_admin, pin,
       created_at, updated_at, google_id, google_avatar_url, github_id, discord_id,
       oidc_issuer, oidc_subject, ldap_dn,
       parent_user_id, avatar_url,
       preferred_audio_lang, preferred_subtitle_lang, max_content_rating
FROM users
WHERE oidc_issuer = $1 AND oidc_subject = $2
`

// GetUserByOIDCSubjectParams scopes the lookup by issuer + subject so two IdPs
// can't collide on the same `sub` value.
type GetUserByOIDCSubjectParams struct {
	OidcIssuer  *string `json:"oidc_issuer"`
	OidcSubject *string `json:"oidc_subject"`
}

func (q *Queries) GetUserByOIDCSubject(ctx context.Context, arg GetUserByOIDCSubjectParams) (User, error) {
	row := q.db.QueryRow(ctx, getUserByOIDCSubject, arg.OidcIssuer, arg.OidcSubject)
	var i User
	err := row.Scan(
		&i.ID,
		&i.Username,
		&i.Email,
		&i.PasswordHash,
		&i.IsAdmin,
		&i.Pin,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.GoogleID,
		&i.GoogleAvatarUrl,
		&i.GithubID,
		&i.DiscordID,
		&i.OidcIssuer,
		&i.OidcSubject,
		&i.LdapDn,
		&i.ParentUserID,
		&i.AvatarUrl,
		&i.PreferredAudioLang,
		&i.PreferredSubtitleLang,
		&i.MaxContentRating,
	)
	return i, err
}

const linkOIDCAccount = `-- name: LinkOIDCAccount :exec
UPDATE users
SET oidc_issuer = $2,
    oidc_subject = $3,
    email = COALESCE(email, $4),
    updated_at = NOW()
WHERE id = $1
`

type LinkOIDCAccountParams struct {
	ID          uuid.UUID `json:"id"`
	OidcIssuer  *string   `json:"oidc_issuer"`
	OidcSubject *string   `json:"oidc_subject"`
	Email       *string   `json:"email"`
}

func (q *Queries) LinkOIDCAccount(ctx context.Context, arg LinkOIDCAccountParams) error {
	_, err := q.db.Exec(ctx, linkOIDCAccount, arg.ID, arg.OidcIssuer, arg.OidcSubject, arg.Email)
	return err
}

